// Captura os valores
const data = $input.first().json.body.data.key;

const jid1 = data.remoteJid;
const jid2 = data.remoteJidAlt;

// Função para extrair e formatar o JID
function formatWhatsApp(jid) {
  if (typeof jid !== 'string' || !jid) return null;

  // Pega somente a parte antes do @
  let base = jid.split('@')[0].trim();
  if (!base) return null;

  // Adiciona @s.whatsapp.net
  return `${base}@s.whatsapp.net`;
}

// Prioriza o primeiro válido, depois o segundo
let result = formatWhatsApp(jid1) || formatWhatsApp(jid2);

// Saída formatada
return [
  {
    json: {
      whatsappJid: result
    }
  }
];

